import React from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const BlogCard = ({ blog, onDelete }) => {
  const navigate = useNavigate();
  const isAdmin = localStorage.getItem('role') === 'admin';

  // ✅ Prevent rendering if blog data is missing
  if (!blog || typeof blog !== 'object') return null;

  const handleDelete = async () => {
    try {
      await axios.delete(`http://localhost:5000/api/blogs/${blog.id}`);
      onDelete(blog.id);
    } catch (error) {
      console.error('Failed to delete blog:', error);
    }
  };

  const imageUrl = blog?.image_url || 'https://via.placeholder.com/600x300?text=Blog+Image';
  const title = blog?.title || 'Untitled Blog';
  const category = blog?.category_name || 'General';
  const date = blog?.created_at
    ? new Date(blog.created_at).toLocaleDateString()
    : 'Unknown Date';

  return (
    <div className="bg-white shadow-lg rounded-lg overflow-hidden w-full sm:w-[48%] md:w-[30%] lg:w-[23%] m-2">
      <img
        src={imageUrl}
        alt={title}
        className="w-full h-48 object-cover"
      />
      <div className="p-4 flex flex-col justify-between h-48">
        <div>
          <h2 className="text-xl font-semibold text-gray-800 mb-2 line-clamp-2">{title}</h2>
          <p className="text-sm text-gray-500 mb-1">
            Category: <span className="font-medium text-indigo-600">{category}</span>
          </p>
          <p className="text-sm text-gray-400 mb-2">Posted on {date}</p>
        </div>
        <div className="flex justify-between items-center">
          <button
            onClick={() => navigate(`/blog/${blog.id}`)}
            className="text-sm bg-blue-600 hover:bg-blue-700 text-white px-3 py-1 rounded transition duration-200"
          >
            Read More
          </button>
          {isAdmin && (
            <button
              onClick={handleDelete}
              className="text-sm bg-red-600 hover:bg-red-700 text-white px-3 py-1 rounded transition duration-200"
            >
              Delete
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default BlogCard;
